const response = $input.first().json;
const policies = response.list || [];
if (policies.length === 0) return [];

// LOB → segment mapping
const commercialLOBs = [
  'commercial auto', 'general liability', 'workers comp', 'commercial property',
  'bop', 'professional liability', 'umbrella', 'builders risk', 'inland marine',
  'commercial package', 'garagekeepers'
];
const personalLOBs = [
  'personal auto', 'homeowners', 'renters', 'condo', 'dwelling fire',
  'motorcycle', 'boat', 'rv', 'life', 'health', 'medicare', 'group benefits'
];

return policies.map(p => {
  const lob = (p.lineOfBusiness || '').toLowerCase();
  const isCommercial = commercialLOBs.some(l => lob.includes(l));
  const segment = isCommercial ? 'Commercial Lines' : 'Personal Lines';
  const leadTimeDays = isCommercial ? 90 : 30;

  const expirationDate = p.expirationDate || null;
  const daysToExp = expirationDate
    ? Math.ceil((new Date(expirationDate) - new Date()) / (1000*60*60*24))
    : null;

  // Skip if outside this segment's lead time
  if (daysToExp !== null && daysToExp > leadTimeDays) return null;

  let urgency = 'Future (60+ days)';
  if (daysToExp <= 7)        urgency = 'Critical (0-7 days)';
  else if (daysToExp <= 14)  urgency = 'Urgent (8-14 days)';
  else if (daysToExp <= 30)  urgency = 'Attention (15-30 days)';
  else if (daysToExp <= 60)  urgency = 'On Track (31-60 days)';

  // Assigned user: Personal → Gretchen, Commercial → Lamar
  const assignedUserId = isCommercial ? '69bdad92458da2204' : '69bdf81552aaa';

  const clientName = p.contactName || p.accountName || 'Unknown Client';
  const renewalName = clientName + ' — ' + (p.lineOfBusiness || 'Policy') + ' Renewal';

  return {
    json: {
      policyId: p.id,
      policyNumber: p.name,
      clientName,
      renewalName,
      expirationDate,
      daysToExp,
      segment,
      lineOfBusiness: p.lineOfBusiness || 'Other',
      carrier: p.carrier || '',
      currentPremium: p.premiumAtRisk || p.premiumAmount || 0,
      commissionRate: p.commissionRate || 0,
      urgency,
      contactId: p.contactId || null,
      accountId: p.accountId || null,
      assignedUserId
    }
  };
}).filter(Boolean);

const checkResult = $input.first().json;
const policyData = $('Loop Policies').first().json;

// If a pending Renewal already exists, skip
const existingCount = checkResult.total || 0;
if (existingCount > 0) {
  return [{ json: { ...policyData, action: 'skip', existingRenewalId: checkResult.list[0].id } }];
}

return [{ json: { ...policyData, action: 'create' } }];

// Collect stats from all created renewals for the Slack digest
const allItems = $('Create Renewal').all();
const created = allItems.filter(i => i.json.id); // successfully created

let totalPremium = 0;
let commercialCount = 0;
let personalCount = 0;
let commercialPremium = 0;
let personalPremium = 0;

for (const item of created) {
  const premium = item.json.currentPremium || 0;
  totalPremium += premium;
  if (item.json.businessSegment === 'Commercial Lines') {
    commercialCount++;
    commercialPremium += premium;
  } else {
    personalCount++;
    personalPremium += premium;
  }
}

// Also count total active renewals
const allPolicies = $('Filter & Map Policies').all();
const skipped = allPolicies.length - created.length;

if (created.length === 0) {
  return [{ json: { sendSlack: false, message: 'No new renewals to create today.' } }];
}

const fmt = (n) => '$' + Number(n).toLocaleString('en-US', { minimumFractionDigits: 0 });

const slackText = `:arrows_counterclockwise: *RSG Renewal Pipeline — Daily Auto-Generator*\n\n` +
  `*New Renewals Created:* ${created.length}\n` +
  `*Already Tracked:* ${skipped}\n\n` +
  `*By Segment:*\n` +
  `  Commercial Lines: ${commercialCount} renewals (${fmt(commercialPremium)} premium at risk)\n` +
  `  Personal Lines: ${personalCount} renewals (${fmt(personalPremium)} premium at risk)\n\n` +
  `*Total Premium at Risk:* ${fmt(totalPremium)}\n\n` +
  created.map(r => `  • ${r.json.name} — ${r.json.carrier || 'TBD'} — ${r.json.expirationDate} — ${fmt(r.json.currentPremium || 0)}`).join('\n') +
  `\n\n<https://rrespocrm-rsg-u69864.vm.elestio.app/#Renewal|View Renewal Pipeline>`;

return [{ json: { sendSlack: true, slackText } }];
